import functools

def logger(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # print Calling message
        # call original function
        # print Done message
        # return result
        pass
    return wrapper

@logger
def greet(name):
    return f'Hello, {name}!'

result = greet('Vaathiyaar')
print(result)
